Erreurs : 1) Une méthode abstraite ne peut pas avoir d'implémentation (faireDuBruit a un corps). 2) Une méthode abstraite doit avoir un type de retour explicite (dormir manque `: void`). 3) On ne peut pas instancier une classe abstraite (`new Animal` est interdit).

Version corrigée :
```typescript
abstract class Animal {
  constructor(public nom: string) {}

  abstract faireDuBruit(): void; // pas de corps

  abstract dormir(): void;

  manger(): void {
    console.log(`${this.nom} mange.`);
  }
}

// const a = new Animal("Inconnu"); // ❌ Interdit
```

```typescript
abstract class Forme {
  constructor(public couleur: string) {}

  afficherCouleur(): void {
    console.log(`Couleur : ${this.couleur}`);
  }

  abstract aire(): number;
  abstract perimetre(): number;
}

class Cercle extends Forme {
  constructor(couleur: string, public rayon: number) {
    super(couleur);
  }

  aire(): number {
    return Math.PI * this.rayon ** 2;
  }

  perimetre(): number {
    return 2 * Math.PI * this.rayon;
  }
}

class Rectangle extends Forme {
  constructor(couleur: string, public largeur: number, public hauteur: number) {
    super(couleur);
  }

  aire(): number {
    return this.largeur * this.hauteur;
  }

  perimetre(): number {
    return 2 * (this.largeur + this.hauteur);
  }
}

class Triangle extends Forme {
  constructor(couleur: string, public a: number, public b: number, public c: number) {
    super(couleur);
  }

  aire(): number {
    const s = (this.a + this.b + this.c) / 2;
    return Math.sqrt(s * (s - this.a) * (s - this.b) * (s - this.c));
  }

  perimetre(): number {
    return this.a + this.b + this.c;
  }
}

// Instanciation
const cercle = new Cercle("rouge", 5);
const rectangle = new Rectangle("bleu", 4, 6);
const triangle = new Triangle("vert", 3, 4, 5);

console.log(`Cercle - Aire: ${cercle.aire()}, Périmètre: ${cercle.perimetre()}`);
console.log(`Rectangle - Aire: ${rectangle.aire()}, Périmètre: ${rectangle.perimetre()}`);
console.log(`Triangle - Aire: ${triangle.aire()}, Périmètre: ${triangle.perimetre()}`);
```

```typescript
abstract class ModePaiement {
  constructor(public nom: string) {}

  afficherNom(): void {
    console.log(`Mode de paiement : ${this.nom}`);
  }

  abstract valider(): boolean;
  abstract payer(montant: number): boolean;
}

class CarteBancaire extends ModePaiement {
  constructor(private numeroCarte: string, private dateExp: string, private cryptogramme: string) {
    super("Carte bancaire");
  }

  valider(): boolean {
    // Validation simplifiée
    return this.numeroCarte.length === 16 && this.cryptogramme.length === 3;
  }

  payer(montant: number): boolean {
    if (!this.valider()) {
      console.log("❌ Carte invalide");
      return false;
    }
    console.log(`💳 Paiement de ${montant} FCFA par carte bancaire.`);
    return true;
  }
}

class MobileMoney extends ModePaiement {
  constructor(private numeroTel: string, private solde: number) {
    super("Mobile Money");
  }

  valider(): boolean {
    return this.numeroTel.length === 9 && this.solde > 0;
  }

  payer(montant: number): boolean {
    if (!this.valider()) {
      console.log("❌ Compte Mobile Money invalide ou solde insuffisant");
      return false;
    }
    if (this.solde < montant) {
      console.log("❌ Solde insuffisant pour Mobile Money");
      return false;
    }
    this.solde -= montant;
    console.log(`📱 Paiement de ${montant} FCFA par Mobile Money. Nouveau solde : ${this.solde} FCFA`);
    return true;
  }
}

class PayPal extends ModePaiement {
  constructor(private email: string, private compteValide: boolean) {
    super("PayPal");
  }

  valider(): boolean {
    return this.email.includes("@") && this.compteValide;
  }

  payer(montant: number): boolean {
    if (!this.valider()) {
      console.log("❌ Compte PayPal non valide");
      return false;
    }
    // Ajout de frais de 2%
    const frais = montant * 0.02;
    const total = montant + frais;
    console.log(`🌐 Paiement de ${montant} FCFA + frais (${frais} FCFA) = ${total} FCFA via PayPal.`);
    return true;
  }
}

function effectuerPaiement(paiement: ModePaiement, montant: number): void {
  paiement.afficherNom();
  if (paiement.valider()) {
    paiement.payer(montant);
  } else {
    console.log("⚠️ Validation échouée, paiement impossible.");
  }
}

// Tests
const cb = new CarteBancaire("1234567812345678", "12/28", "123");
const mm = new MobileMoney("691234567", 50000);
const pp = new PayPal("client@example.com", true);

effectuerPaiement(cb, 15000);
effectuerPaiement(mm, 30000);
effectuerPaiement(pp, 75000);
```
